  ('disabled-6f0ba476-moex-00423', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '按照財務報導之觀念架構，下列何種衡量基礎不須考量交易成本？①歷史成', '["現時成本", "公允價值", "資產之使用價值  ⑤負債之履約價值", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00424', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X2 年度損益相關資料如下：資產重估價損失$60,000、外幣兌換利 益$80,000，國外營運機構財務報表換算差額（貸餘）$150,000、透過其他綜 合損益按公允價值衡量之股票投資未實現評價損失$30,000、停業單位損失 $90,000，則X2年度本期其他綜合（損）益為何？（不考慮所得稅影響）', '["$60,000", "$120,000", "$140,000", "$200,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00425', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', 'X3 年初甲公司有 1,000,000 股普通股發行流通在外，4 月 1 日另發行 600,000股普通股，10月1日甲公司平價發行10,000張面值$1,000，8%的 可轉換公司債，每張公司債可轉換 40 股普通股。當時相同條件無轉換權 之公司債公允價值為$900，有效利率10%，X3年度並無轉換。甲公司X3 年度淨利為$5,800,000，所得稅率20%，則X3年稀釋每股盈餘為何？', '["$3.110", "$3.845", "$3.858", "$3.887"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00426', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 7 月 31 日銀行對帳單上之存款餘額為$640,000，7 月底在途存款為 $90,000、未兌現支票為$120,000。7 月份因存款不足而退票$40,000，其中 $24,000 又於 7 月底前存入。7 月 30 日銀行誤將兌付丁公司之支票$35,000 誤自甲公司帳戶中扣除，銀行尚未發現此錯誤。7月份銀行代收票據$56,000 ，並扣除手續費$1,000。甲公司7月31日帳上之存款餘額是多少？', '["$606,000", "$614,000", "$574,000", "$590,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00427', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X2年度綜合損益表中稅前淨利為$70,100，審計人員發現其中包含', '["透過其他綜合損益按公允價值衡量之債務工具投資未實現評 價損失$5,400；", "透過其他綜合損益按公允價值衡量之權益工具投資處分 利益$3,000；", "提前贖回債券利益$22,000；", "X1 年度少計提折舊之追溯 重編影響數$7,500；⑤火災損失$7,000。甲公司X2年度稅前淨利應為："]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00428', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X2年12月31日期末原料成本為$800,000，重置成本$750,000；期 末在製品1,000單位，成本$231,000，估計至完工尚須投入成本$250,000； 期末製成品2,000單位，成本$1,000,000。每單位產品售價為$500，銷售費 用估計為售價的 8%，正常利潤率估計為售價的 12%，則甲公司 X2 年 12 月31日應報導期末存貨是多少？', '["$1,550,000", "$1,820,000", "$1,880,000", "$1,930,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00429', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X1 年期末經盤點確定庫存貨品成本共有$525,000，檢視相關資料', '["目的地交貨之進貨$3,000，X2年1月8日才運達；", "承銷丙公司商品尚未賣出，計有$15,000；", "X1年12月簽訂售後買回合約 ，出售商品給客戶，售價$32,000，成本$12,400，銷售合約給予甲公司一項 買權，甲公司可於 X2年2月按$28,000再買回該商品。試問甲公司X1年 期末正確存貨成本應該為多少？", "$510,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00430', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X3年1月3日以$3,500,000取得丙公司40%普通股股權，經評估 具重大影響，同時按股權淨值取得丙公司 50%特別股權益。丙公司 X2 年 底資產負債表上之權益如下：5%累積特別股股本$2,000,000（面額$100，收 回價格$110，積欠兩年股利）；普通股股本$6,000,000（面額$10）；資本公 積$2,000,000；保留盈餘$600,000。假設投資成本與所享有丙公司權益份額 之差額分五年攤銷，X3年度淨利為$600,000，X3年度宣告並發放現金股利 $400,000，X4 年度淨利為$200,000，未發放股利。假設甲公司與丙公司間 並未發生其他交易，則有關前述投資之會計處理，下列何者錯誤？', '["甲公司X3年底對丙公司普通股投資帳戶餘額為$3,660,000", "甲公司X4年底對丙公司普通股投資帳戶餘額為$3,612,000", "甲公司X3年度對丙公司普通股投資之相關投資收益為$156,000", "甲公司X4年度對丙公司普通股投資之相關投資損失為$4,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
